--!strict
-- RatUI Mercury-style ultra UI framework
local Players = game:GetService("Players")
local RunService = game:GetService("RunService")
local TweenService = game:GetService("TweenService")
local UserInputService = game:GetService("UserInputService")
local Lighting = game:GetService("Lighting")
local LocalPlayer = Players.LocalPlayer

local RatUI = {}
RatUI.__index = RatUI
local RatWindow = {}
RatWindow.__index = RatWindow
local RatTab = {}
RatTab.__index = RatTab

local function create(className, props, children)
    local i = Instance.new(className)
    for k, v in pairs(props or {}) do i[k] = v end
    for _, c in ipairs(children or {}) do c.Parent = i end
    return i
end

local function corner(r) return create("UICorner", { CornerRadius = UDim.new(0, r) }) end
local function stroke(c, t, tr) return create("UIStroke", { Color = c, Thickness = t or 1, Transparency = tr or 0, ApplyStrokeMode = Enum.ApplyStrokeMode.Border }) end
local function pad(px) return create("UIPadding", { PaddingLeft = UDim.new(0, px), PaddingRight = UDim.new(0, px), PaddingTop = UDim.new(0, px), PaddingBottom = UDim.new(0, px) }) end

local function prettyTime(seconds)
    local h = math.floor(seconds / 3600)
    local m = math.floor((seconds % 3600) / 60)
    local s = math.floor(seconds % 60)
    return string.format("%02d:%02d:%02d", h, m, s)
end

local function makeDraggable(handle, root)
    local startPos, dragStart
    handle.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1 then
            dragStart = input.Position
            startPos = root.Position
        end
    end)
    UserInputService.InputEnded:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1 then dragStart = nil startPos = nil end
    end)
    UserInputService.InputChanged:Connect(function(input)
        if not dragStart or not startPos then return end
        if input.UserInputType ~= Enum.UserInputType.MouseMovement then return end
        local delta = input.Position - dragStart
        root.Position = UDim2.new(startPos.X.Scale, startPos.X.Offset + delta.X, startPos.Y.Scale, startPos.Y.Offset + delta.Y)
    end)
end

local DefaultTheme = {
    Background = Color3.fromRGB(13, 14, 18),
    Surface = Color3.fromRGB(18, 20, 27),
    SurfaceLight = Color3.fromRGB(26, 29, 39),
    Elevated = Color3.fromRGB(31, 35, 46),
    Text = Color3.fromRGB(236, 239, 245),
    SubText = Color3.fromRGB(145, 153, 171),
    Accent = Color3.fromRGB(116, 104, 255),
    Positive = Color3.fromRGB(95, 226, 128),
    Negative = Color3.fromRGB(251, 90, 109),
    Warning = Color3.fromRGB(253, 193, 86),
}

function RatUI.new(config)
    config = config or {}
    local self = setmetatable({}, RatUI)
    self.Theme = config.Theme or DefaultTheme
    self.ScriptName = config.ScriptName or "RatUI"
    self.ToggleKey = config.ToggleKey or Enum.KeyCode.RightShift
    self.Started = os.clock()
    self._fps = 0
    self._frames = 0
    self._acc = 0
    self._connections = {}
    self._notifications = {}
    self._windows = {}
    return self
end

function RatUI:CreateWindow(options)
    options = options or {}
    local window = setmetatable({}, RatWindow)
    window._ui = self
    window.Theme = options.Theme or self.Theme
    window.Title = options.Title or "RatUI Window"
    window.Subtitle = options.Subtitle or "Mercury-inspired interface"
    window._tabs = {}
    window._keybinds = {}
    window._listeningBind = nil
    local pg = LocalPlayer:WaitForChild("PlayerGui")
    window.Gui = create("ScreenGui", { Name = "RatUI", IgnoreGuiInset = true, ResetOnSpawn = false, Parent = pg })
    window.Root = create("Frame", { BackgroundTransparency = 1, Size = UDim2.fromScale(1,1), Parent = window.Gui })
    window.Blur = create("BlurEffect", { Name = "RatUIBlur", Size = options.BlurSize or 10, Enabled = options.Blur ~= false, Parent = Lighting })
    window.Watermark = create("Frame", { Position = UDim2.fromOffset(16, 14), Size = UDim2.fromOffset(430, 36), BackgroundColor3 = window.Theme.Surface, BorderSizePixel = 0, Parent = window.Root }, { corner(9), stroke(window.Theme.Accent, 1, 0.25) })
    window.WatermarkLabel = create("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(10,0), Size = UDim2.new(1,-20,1,0), Font = Enum.Font.GothamSemibold, Text = "", TextXAlignment = Enum.TextXAlignment.Left, TextSize = 13, RichText = true, TextColor3 = window.Theme.Text, Parent = window.Watermark })
    window.Main = create("Frame", { AnchorPoint = Vector2.new(0.5,0.5), Position = UDim2.fromScale(0.5,0.52), Size = UDim2.fromOffset(940, 580), BackgroundColor3 = window.Theme.Background, BorderSizePixel = 0, Parent = window.Root }, { corner(14), stroke(window.Theme.Accent,1,0.5) })
    window.Topbar = create("Frame", { Size = UDim2.new(1,0,0,56), BackgroundColor3 = window.Theme.Surface, BorderSizePixel = 0, Parent = window.Main }, { corner(14) })
    create("Frame", { Position = UDim2.new(0,0,1,-14), Size = UDim2.new(1,0,0,14), BackgroundColor3 = window.Theme.Surface, BorderSizePixel = 0, Parent = window.Topbar })
    window.TitleLabel = create("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(16,0), Size = UDim2.fromOffset(350,56), Font = Enum.Font.GothamBold, Text = window.Title, TextSize = 17, TextColor3 = window.Theme.Text, TextXAlignment = Enum.TextXAlignment.Left, Parent = window.Topbar })
    window.SubLabel = create("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(180,0), Size = UDim2.fromOffset(380,56), Font = Enum.Font.Gotham, Text = window.Subtitle, TextSize = 13, TextColor3 = window.Theme.SubText, TextXAlignment = Enum.TextXAlignment.Left, Parent = window.Topbar })
    window.KeyHint = create("TextLabel", { BackgroundTransparency = 1, AnchorPoint = Vector2.new(1,0), Position = UDim2.new(1,-16,0,0), Size = UDim2.fromOffset(200,56), Font = Enum.Font.GothamSemibold, Text = "Toggle: " .. tostring(self.ToggleKey.Name), TextSize = 12, TextColor3 = window.Theme.SubText, TextXAlignment = Enum.TextXAlignment.Right, Parent = window.Topbar })
    window.Sidebar = create("Frame", { Position = UDim2.fromOffset(12,68), Size = UDim2.new(0,220,1,-80), BackgroundColor3 = window.Theme.Surface, BorderSizePixel = 0, Parent = window.Main }, { corner(12) })
    window.TabScroller = create("ScrollingFrame", { BackgroundTransparency = 1, BorderSizePixel = 0, Position = UDim2.fromOffset(8,8), Size = UDim2.new(1,-16,1,-16), ScrollBarThickness = 2, CanvasSize = UDim2.new(0,0,0,0), AutomaticCanvasSize = Enum.AutomaticSize.Y, Parent = window.Sidebar }, { create("UIListLayout", { Padding = UDim.new(0,6), SortOrder = Enum.SortOrder.LayoutOrder }) })
    window.Content = create("Frame", { Position = UDim2.fromOffset(244,68), Size = UDim2.new(1,-256,1,-80), BackgroundColor3 = window.Theme.Surface, BorderSizePixel = 0, Parent = window.Main }, { corner(12) })
    window.NotificationHolder = create("Frame", { AnchorPoint = Vector2.new(1,1), Position = UDim2.new(1,-16,1,-16), Size = UDim2.fromOffset(330, 260), BackgroundTransparency = 1, Parent = window.Root }, { create("UIListLayout", { Padding = UDim.new(0,6), SortOrder = Enum.SortOrder.LayoutOrder, VerticalAlignment = Enum.VerticalAlignment.Bottom, HorizontalAlignment = Enum.HorizontalAlignment.Right }) })
    window.TargetHUD = create("Frame", { AnchorPoint = Vector2.new(1,0), Position = UDim2.new(1,-16,0,56), Size = UDim2.fromOffset(350,136), BackgroundColor3 = window.Theme.Surface, BorderSizePixel = 0, Parent = window.Root }, { corner(11), stroke(window.Theme.Accent,1,0.3) })
    window.TargetName = create("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(14,10), Size = UDim2.new(1,-28,0,24), Font = Enum.Font.GothamBold, Text = "No Target", TextSize = 16, TextXAlignment = Enum.TextXAlignment.Left, TextColor3 = window.Theme.Text, Parent = window.TargetHUD })
    window.TargetDistance = create("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(14,34), Size = UDim2.new(1,-28,0,20), Font = Enum.Font.Gotham, Text = "Distance: --", TextSize = 13, TextXAlignment = Enum.TextXAlignment.Left, TextColor3 = window.Theme.SubText, Parent = window.TargetHUD })
    window.TargetHealthBack = create("Frame", { Position = UDim2.fromOffset(14,64), Size = UDim2.new(1,-28,0,20), BackgroundColor3 = window.Theme.Elevated, BorderSizePixel = 0, Parent = window.TargetHUD }, { corner(9) })
    window.TargetHealthFill = create("Frame", { Size = UDim2.fromScale(0,1), BackgroundColor3 = window.Theme.Positive, BorderSizePixel = 0, Parent = window.TargetHealthBack }, { corner(9) })
    window.TargetHealthLabel = create("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(14,90), Size = UDim2.new(1,-28,0,20), Font = Enum.Font.GothamSemibold, Text = "Health: --", TextSize = 12, TextXAlignment = Enum.TextXAlignment.Left, TextColor3 = window.Theme.Text, Parent = window.TargetHUD })
    window.Keybinds = create("Frame", { AnchorPoint = Vector2.new(0,1), Position = UDim2.new(0,16,1,-16), Size = UDim2.fromOffset(310,220), BackgroundColor3 = window.Theme.Surface, BorderSizePixel = 0, Parent = window.Root }, { corner(11), stroke(window.Theme.Accent,1,0.3) })
    create("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(12,8), Size = UDim2.new(1,-24,0,22), Font = Enum.Font.GothamBold, Text = "Keybinds", TextSize = 14, TextXAlignment = Enum.TextXAlignment.Left, TextColor3 = window.Theme.Text, Parent = window.Keybinds })
    window.KeybindList = create("Frame", { Position = UDim2.fromOffset(12,34), Size = UDim2.new(1,-24,1,-42), BackgroundTransparency = 1, Parent = window.Keybinds }, { create("UIListLayout", { Padding = UDim.new(0,4), SortOrder = Enum.SortOrder.LayoutOrder }) })
    makeDraggable(window.Topbar, window.Main)
    makeDraggable(window.TargetHUD, window.TargetHUD)
    makeDraggable(window.Keybinds, window.Keybinds)
    table.insert(self._windows, window)
    window:_connectRuntime()
    return window
end

function RatWindow:_connectRuntime()
    local ui = self._ui
    table.insert(ui._connections, UserInputService.InputBegan:Connect(function(input, gp)
        if gp then return end
        if self._listeningBind then
            if input.UserInputType == Enum.UserInputType.Keyboard then self._listeningBind.key = input.KeyCode if self._listeningBind.button then self._listeningBind.button.Text = input.KeyCode.Name end self:_refreshKeybindList() end
            self._listeningBind = nil
            return
        end
        if input.KeyCode == ui.ToggleKey then self.Main.Visible = not self.Main.Visible return end
        for _, bind in ipairs(self._keybinds) do if bind.key == input.KeyCode and bind.callback then bind.callback() end end
    end))
    table.insert(ui._connections, RunService.RenderStepped:Connect(function(dt)
        ui._frames += 1
        ui._acc += dt
        if ui._acc >= 0.25 then
            ui._fps = math.floor(ui._frames / ui._acc + 0.5)
            ui._frames = 0
            ui._acc = 0
            local uptime = prettyTime(os.clock() - ui.Started)
            local c = self.Theme.Accent
            self.WatermarkLabel.Text = string.format('<font color="rgb(%d,%d,%d)">%s</font> | FPS: %d | Uptime: %s', math.floor(c.R*255), math.floor(c.G*255), math.floor(c.B*255), ui.ScriptName, ui._fps, uptime)
        end
    end))
    self:_refreshKeybindList()
end

function RatWindow:_setActiveTab(tab) for _, t in ipairs(self._tabs) do local active = t == tab t.Button.BackgroundColor3 = active and self.Theme.Accent or self.Theme.Elevated t.Button.TextColor3 = active and Color3.new(1,1,1) or self.Theme.Text t.Page.Visible = active end end
function RatWindow:CreateTab(name, icon) local tab = setmetatable({}, RatTab) tab._window = self tab.Name = name tab.Button = create("TextButton", { AutoButtonColor = false, Size = UDim2.new(1,0,0,36), BackgroundColor3 = self.Theme.Elevated, BorderSizePixel = 0, Text = (icon or "•") .. "  " .. name, Font = Enum.Font.GothamSemibold, TextSize = 13, TextXAlignment = Enum.TextXAlignment.Left, TextColor3 = self.Theme.Text, Parent = self.TabScroller }, { corner(8), pad(10) }) tab.Page = create("ScrollingFrame", { BackgroundTransparency = 1, BorderSizePixel = 0, Position = UDim2.fromOffset(10,10), Size = UDim2.new(1,-20,1,-20), ScrollBarThickness = 3, CanvasSize = UDim2.new(0,0,0,0), AutomaticCanvasSize = Enum.AutomaticSize.Y, Visible = false, Parent = self.Content }, { create("UIListLayout", { Padding = UDim.new(0,8), SortOrder = Enum.SortOrder.LayoutOrder }) }) tab.Button.MouseButton1Click:Connect(function() self:_setActiveTab(tab) end) table.insert(self._tabs, tab) if #self._tabs == 1 then self:_setActiveTab(tab) end return tab end
function RatTab:_card(h) return create("Frame", { Size = UDim2.new(1,0,0,h), BackgroundColor3 = self._window.Theme.Elevated, BorderSizePixel = 0, Parent = self.Page }, { corner(10), stroke(self._window.Theme.SurfaceLight,1,0.5) }) end
function RatTab:AddButton(text, callback) local card=self:_card(46) local b=create("TextButton", {AutoButtonColor=false,Position=UDim2.fromOffset(6,6),Size=UDim2.new(1,-12,1,-12),BackgroundColor3=self._window.Theme.Accent,BorderSizePixel=0,Font=Enum.Font.GothamBold,Text=text,TextSize=13,TextColor3=Color3.new(1,1,1),Parent=card},{corner(8)}) b.MouseButton1Click:Connect(function() if callback then callback() end end) return b end
function RatTab:AddToggle(text, state, callback) local on=state==true local card=self:_card(50) create("TextLabel", {BackgroundTransparency=1,Position=UDim2.fromOffset(10,0),Size=UDim2.new(1,-80,1,0),Font=Enum.Font.GothamSemibold,Text=text,TextSize=13,TextXAlignment=Enum.TextXAlignment.Left,TextColor3=self._window.Theme.Text,Parent=card}) local switch=create("TextButton", {AnchorPoint=Vector2.new(1,0.5),Position=UDim2.new(1,-10,0.5,0),Size=UDim2.fromOffset(46,24),AutoButtonColor=false,Text="",BackgroundColor3=on and self._window.Theme.Accent or self._window.Theme.Surface,BorderSizePixel=0,Parent=card},{corner(20)}) local knob=create("Frame", {Size=UDim2.fromOffset(18,18),Position=on and UDim2.fromOffset(25,3) or UDim2.fromOffset(3,3),BackgroundColor3=Color3.new(1,1,1),BorderSizePixel=0,Parent=switch},{corner(20)}) local function apply() TweenService:Create(switch,TweenInfo.new(0.15),{BackgroundColor3=on and self._window.Theme.Accent or self._window.Theme.Surface}):Play() TweenService:Create(knob,TweenInfo.new(0.15),{Position=on and UDim2.fromOffset(25,3) or UDim2.fromOffset(3,3)}):Play() if callback then callback(on) end end switch.MouseButton1Click:Connect(function() on=not on apply() end) apply() return {Set=function(_,v) on=v and true or false apply() end,Get=function() return on end} end
function RatTab:AddSlider(text,min,max,value,callback) min=min or 0 max=max or 100 local val=math.clamp(value or min,min,max) local card=self:_card(74) local label=create("TextLabel", {BackgroundTransparency=1,Position=UDim2.fromOffset(10,6),Size=UDim2.new(1,-20,0,20),Font=Enum.Font.GothamSemibold,Text=text,TextSize=13,TextXAlignment=Enum.TextXAlignment.Left,TextColor3=self._window.Theme.Text,Parent=card}) local track=create("Frame", {Position=UDim2.fromOffset(10,38),Size=UDim2.new(1,-20,0,22),BackgroundColor3=self._window.Theme.Surface,BorderSizePixel=0,Parent=card},{corner(10)}) local fill=create("Frame", {Size=UDim2.fromScale(0,1),BackgroundColor3=self._window.Theme.Accent,BorderSizePixel=0,Parent=track},{corner(10)}) local dragging=false local function render() local alpha=(val-min)/(max-min) fill.Size=UDim2.fromScale(alpha,1) label.Text=string.format("%s: %.1f",text,val) if callback then callback(val) end end local function setX(x) local alpha=math.clamp((x-track.AbsolutePosition.X)/track.AbsoluteSize.X,0,1) val=min+(max-min)*alpha render() end track.InputBegan:Connect(function(input) if input.UserInputType==Enum.UserInputType.MouseButton1 then dragging=true setX(input.Position.X) end end) UserInputService.InputChanged:Connect(function(input) if dragging and input.UserInputType==Enum.UserInputType.MouseMovement then setX(input.Position.X) end end) UserInputService.InputEnded:Connect(function(input) if input.UserInputType==Enum.UserInputType.MouseButton1 then dragging=false end end) render() return {Set=function(_,v) val=math.clamp(v,min,max) render() end,Get=function() return val end} end
function RatTab:AddKeybind(text,key,callback) local bind={name=text,key=key or Enum.KeyCode.Unknown,callback=callback} table.insert(self._window._keybinds,bind) local card=self:_card(58) create("TextLabel", {BackgroundTransparency=1,Position=UDim2.fromOffset(10,0),Size=UDim2.new(0.55,0,1,0),Font=Enum.Font.GothamSemibold,Text=text,TextSize=13,TextXAlignment=Enum.TextXAlignment.Left,TextColor3=self._window.Theme.Text,Parent=card}) local btn=create("TextButton", {AnchorPoint=Vector2.new(1,0.5),Position=UDim2.new(1,-10,0.5,0),Size=UDim2.fromOffset(120,32),AutoButtonColor=false,BackgroundColor3=self._window.Theme.Surface,BorderSizePixel=0,Text=bind.key.Name,Font=Enum.Font.GothamBold,TextSize=12,TextColor3=self._window.Theme.Text,Parent=card},{corner(8),stroke(self._window.Theme.SurfaceLight,1,0.4)}) bind.button=btn btn.MouseButton1Click:Connect(function() self._window._listeningBind=bind btn.Text="Press key..." end) self._window:_refreshKeybindList() return bind end
function RatWindow:_refreshKeybindList() for _,c in ipairs(self.KeybindList:GetChildren()) do if c:IsA("TextLabel") then c:Destroy() end end if #self._keybinds==0 then create("TextLabel", {BackgroundTransparency=1,Size=UDim2.new(1,0,0,20),Font=Enum.Font.Gotham,Text="No keybinds",TextSize=12,TextXAlignment=Enum.TextXAlignment.Left,TextColor3=self.Theme.SubText,Parent=self.KeybindList}) return end for _,bind in ipairs(self._keybinds) do create("TextLabel", {BackgroundTransparency=1,Size=UDim2.new(1,0,0,20),Font=Enum.Font.GothamSemibold,Text=string.format("%s [%s]",bind.name,bind.key.Name),TextSize=12,TextXAlignment=Enum.TextXAlignment.Left,TextColor3=self.Theme.Text,Parent=self.KeybindList}) end end
function RatWindow:SetTarget(info) info=info or {} local name=tostring(info.name or info.Name or "Unknown") local dist=tonumber(info.distance or info.Distance) or 0 local hp=tonumber(info.health or info.Health) or 0 local mx=math.max(tonumber(info.maxHealth or info.MaxHealth) or 100,1) local r=math.clamp(hp/mx,0,1) self.TargetName.Text=name self.TargetDistance.Text=string.format("Distance: %.1fm",dist) self.TargetHealthLabel.Text=string.format("Health: %d/%d",math.floor(hp+0.5),math.floor(mx+0.5)) TweenService:Create(self.TargetHealthFill,TweenInfo.new(0.15,Enum.EasingStyle.Quad,Enum.EasingDirection.Out),{Size=UDim2.fromScale(r,1),BackgroundColor3=Color3.fromRGB(255-math.floor(130*r),80+math.floor(160*r),110)}):Play() end
function RatWindow:ClearTarget() self.TargetName.Text="No Target" self.TargetDistance.Text="Distance: --" self.TargetHealthLabel.Text="Health: --" self.TargetHealthFill.Size=UDim2.fromScale(0,1) end
function RatWindow:Notify(title,message,duration) duration=duration or 3 local n=create("Frame", {Size=UDim2.new(1,0,0,66),BackgroundColor3=self.Theme.Surface,BorderSizePixel=0,Parent=self.NotificationHolder},{corner(9),stroke(self.Theme.Accent,1,0.3)}) create("TextLabel", {BackgroundTransparency=1,Position=UDim2.fromOffset(10,8),Size=UDim2.new(1,-20,0,20),Font=Enum.Font.GothamBold,Text=tostring(title),TextSize=13,TextXAlignment=Enum.TextXAlignment.Left,TextColor3=self.Theme.Text,Parent=n}) create("TextLabel", {BackgroundTransparency=1,Position=UDim2.fromOffset(10,28),Size=UDim2.new(1,-20,0,30),Font=Enum.Font.Gotham,Text=tostring(message),TextWrapped=true,TextSize=12,TextXAlignment=Enum.TextXAlignment.Left,TextYAlignment=Enum.TextYAlignment.Top,TextColor3=self.Theme.SubText,Parent=n}) task.delay(duration,function() if n.Parent then n:Destroy() end end) end
function RatWindow:SetVisible(v) self.Main.Visible = v and true or false end
function RatWindow:SetScriptName(name) self._ui.ScriptName=tostring(name) end
function RatWindow:SetTitle(title) self.TitleLabel.Text=tostring(title) end
function RatWindow:SetTheme(theme) self.Theme=theme self.Main.BackgroundColor3=theme.Background self.Topbar.BackgroundColor3=theme.Surface self.Sidebar.BackgroundColor3=theme.Surface self.Content.BackgroundColor3=theme.Surface self.Watermark.BackgroundColor3=theme.Surface self.TargetHUD.BackgroundColor3=theme.Surface self.Keybinds.BackgroundColor3=theme.Surface end
function RatWindow:Destroy() if self.Blur then self.Blur:Destroy() end if self.Gui then self.Gui:Destroy() end end

